mapper.select:
SELECT type_id, name, description, created_at
FROM facility_type
WHERE type_id = #{typeId}

mapper.update:
UPDATE facility_type
SET name        = #{name},
    description = #{description}
WHERE type_id = #{typeId}
  AND deleted_at IS NULL

mapper.select:
SELECT COUNT(*) FROM facility
WHERE type_id = #{typeId}
  AND deleted_at IS NULL
